 21→void ALFPTurnManager::BeginPlay()
 22→{
 23→    Super::BeginPlay();
 24→}
 25→
 26→void ALFPTurnManager::StartGame()
 27→{
 28→    // 收集场上所有单位（敌方预放置在关卡中）
 29→    TArray<AActor*> FoundActors;
 30→    UGameplayStatics::GetAllActorsOfClass(GetWorld(), ALFPTacticsUnit::StaticClass(), FoundActors);
 31→
 32→    for (AActor* Actor : FoundActors)
 33→    {
 34→        if (ALFPTacticsUnit* Unit = Cast<ALFPTacticsUnit>(Actor))
 35→        {
 36→            // 仅注册非玩家单位（玩家单位在布置阶段结束后注册）
 37→            if (Unit->GetAffiliation() != EUnitAffiliation::UA_Player)
 38→            {
 39→                TurnOrderUnits.Add(Unit);
 40→            }
 41→        }
 42→    }
 43→
 44→    // 初始化阵营 AP
 45→    FactionCurrentAP.Add(EUnitAffiliation::UA_Player, FactionInitialAP);
 46→    FactionCurrentAP.Add(EUnitAffiliation::UA_Enemy, FactionInitialAP);
 47→    FactionCurrentAP.Add(EUnitAffiliation::UA_Neutral, FactionInitialAP);
 48→
 49→    // 标记为布置阶段（不广播，等 PlayerController 绑定委托后主动调用）
 50→    CurrentPhase = EBattlePhase::BP_Deployment;
 51→}
 52→
 53→void ALFPTurnManager::BeginDeploymentPhase()
 54→{
 55→    SetPhase(EBattlePhase::BP_Deployment);
 56→    UE_LOG(LogTemp, Log, TEXT("布置阶段开始"));
 57→}
 58→
 59→void ALFPTurnManager::EndDeploymentPhase()
 60→{
 61→    UE_LOG(LogTemp, Log, TEXT("布置阶段结束，注册玩家单位"));
 62→
 63→    // 收集布置阶段放置的玩家单位
 64→    TArray<AActor*> FoundActors;
 65→    UGameplayStatics::GetAllActorsOfClass(GetWorld(), ALFPTacticsUnit::StaticClass(), FoundActors);
 66→
 67→    for (AActor* Actor : FoundActors)
 68→    {
 69→        if (ALFPTacticsUnit* Unit = Cast<ALFPTacticsUnit>(Actor))
 70→        {
 71→            if (Unit->GetAffiliation() == EUnitAffiliation::UA_Player && !TurnOrderUnits.Contains(Unit))
 72→            {
 73→                TurnOrderUnits.Add(Unit);
 74→            }
 75→        }
 76→    }
 77→
 78→    // 开始第一回合
 79→    BeginNewRound();
 80→}
 81→
 82→void ALFPTurnManager::BeginNewRound()
 83→{
 84→    if (bBattleEnded) return;
 85→
 86→    CurrentRound++;
 87→    bIsInRound = true;
 88→
 89→    // 重置所有单位
 90→    for (ALFPTacticsUnit* Unit : TurnOrderUnits)
 91→    {
 92→        if (Unit && Unit->IsValidLowLevel())
 93→        {
 94→            Unit->ResetForNewRound();
 95→        }
 96→    }
 97→
 98→    // 按速度排序单位
 99→    SortUnitsBySpeed();
100→
101→    // 清空上一轮的敌人计划
102→    EnemyActionPlans.Empty();
103→    AllocatedSkills.Empty();
104→
105→    // 恢复阵营 AP
106→    for (auto& Pair : FactionCurrentAP)
107→    {
108→        Pair.Value = FMath::Min(Pair.Value + FactionAPRecovery, FactionMaxAP);
109→        OnFactionAPChanged.Broadcast(Pair.Key, Pair.Value);
110→    }
111→
112→    // 进入敌人规划阶段
113→    BeginEnemyPlanningPhase();
114→}
115→
116→void ALFPTurnManager::EndCurrentRound()
117→{
118→    if (bBattleEnded) return;
119→
120→    bIsInRound = false;
121→
122→    SetPhase(EBattlePhase::BP_RoundEnd);
123→
124→    // 通知玩家本回合结束
125→    for (FConstPlayerControllerIterator It = GetWorld()->GetPlayerControllerIterator(); It; ++It)
126→    {
127→        if (ALFPTacticsPlayerController* PC = Cast<ALFPTacticsPlayerController>(*It))
128→        {
129→            PC->OnRoundEnded(CurrentRound);
130→        }
131→    }
132→
133→    // 添加延迟后开始新回合
134→    FTimerHandle TimerHandle;
135→    GetWorld()->GetTimerManager().SetTimer(TimerHandle, this, &ALFPTurnManager::BeginNewRound, 0.5f, false);
136→}
