147→// ==== 阶段管理 ====
148→
149→void ALFPTurnManager::SetPhase(EBattlePhase NewPhase)
150→{
151→    CurrentPhase = NewPhase;
152→    UE_LOG(LogTemp, Log, TEXT("SetPhase:=%d"), NewPhase);
153→    OnPhaseChanged.Broadcast(NewPhase);
154→}
