156→// ==== 敌人规划阶段 ====
157→
158→void ALFPTurnManager::BeginEnemyPlanningPhase()
159→{
160→    SetPhase(EBattlePhase::BP_EnemyPlanning);
161→
162→    // 过滤出存活的敌方单位，按速度排序
163→    PlanningOrderEnemies.Empty();
164→    for (ALFPTacticsUnit* Unit : TurnOrderUnits)
165→    {
166→        if (Unit && Unit->IsAlive() && Unit->IsEnemy())
167→        {
168→            PlanningOrderEnemies.Add(Unit);
169→        }
170→    }
171→
172→    // 敌方单位已按速度排序（继承自 TurnOrderUnits 的排序）
173→
174→    CurrentPlanningEnemyIndex = 0;
175→
176→    if (PlanningOrderEnemies.Num() == 0)
177→    {
178→        // 没有敌方单位，直接进入行动阶段
179→        EndEnemyPlanningPhase();
180→        return;
181→    }
182→
183→    // 隐藏玩家技能选择UI
184→    if (ALFPTacticsPlayerController* PC = GetWorld()->GetFirstPlayerController<ALFPTacticsPlayerController>())
185→    {
186→        PC->HideSkillSelection();
187→    }
188→
189→    // Step 1: 全局技能分配（按优先级分配AP技能）
190→    AllocateEnemySkills();
191→
192→    // Step 2: 按速度顺序移动展示
193→    ProcessNextEnemyPlan();
194→}
195→
196→void ALFPTurnManager::ProcessNextEnemyPlan()
197→{
198→    if (CurrentPlanningEnemyIndex >= PlanningOrderEnemies.Num())
199→    {
200→        // 所有敌人规划完毕
201→        EndEnemyPlanningPhase();
202→        return;
203→    }
204→
205→    ALFPTacticsUnit* Enemy = PlanningOrderEnemies[CurrentPlanningEnemyIndex];
206→
207→    // 跳过死亡单位
208→    if (!Enemy || !Enemy->IsAlive())
209→    {
210→        CurrentPlanningEnemyIndex++;
211→        ProcessNextEnemyPlan();
212→        return;
213→    }
214→
215→    ALFPAIController* AIController = Enemy->GetAIController();
216→    if (!AIController)
217→    {
218→        CurrentPlanningEnemyIndex++;
219→        ProcessNextEnemyPlan();
220→        return;
221→    }
222→
223→    // 移动前等待，让玩家观察当前局势
224→    FTimerHandle TimerHandle;
225→    GetWorld()->GetTimerManager().SetTimer(
226→        TimerHandle,
227→        this,
228→        &ALFPTurnManager::ExecuteCurrentEnemyPlan,
229→        EnemyPlanPreMoveDelay,
230→        false
231→    );
232→}
233→
234→void ALFPTurnManager::ExecuteCurrentEnemyPlan()
235→{
236→    if (CurrentPlanningEnemyIndex >= PlanningOrderEnemies.Num())
237→    {
238→        EndEnemyPlanningPhase();
239→        return;
240→    }
241→
242→    ALFPTacticsUnit* Enemy = PlanningOrderEnemies[CurrentPlanningEnemyIndex];
243→    if (!Enemy || !Enemy->IsAlive())
244→    {
245→        CurrentPlanningEnemyIndex++;
246→        ProcessNextEnemyPlan();
247→        return;
248→    }
249→
250→    ALFPAIController* AIController = Enemy->GetAIController();
251→    if (!AIController)
252→    {
253→        CurrentPlanningEnemyIndex++;
254→        ProcessNextEnemyPlan();
255→        return;
256→    }
257→
258→    // 创建行动计划，传入预分配的技能
259→    ULFPSkillBase* PreAllocatedSkill = nullptr;
260→    if (ULFPSkillBase** Found = AllocatedSkills.Find(Enemy))
261→    {
262→        PreAllocatedSkill = *Found;
263→    }
264→    FEnemyActionPlan Plan = AIController->CreateActionPlan(PreAllocatedSkill);
265→
266→    // 存储计划
267→    EnemyActionPlans.Add(Plan);
268→    Enemy->SetActionPlan(Plan);
269→
270→    // 推进到下一个敌人
271→    CurrentPlanningEnemyIndex++;
272→
273→    // 如果敌人正在移动，等移动完成后再推进
274→    if (Enemy->bIsMoving)
275→    {
276→        // 记录当前移动中的敌人，回调中需要解绑
277→        PlanningMovingEnemy = Enemy;
278→        Enemy->OnMoveFinished.AddDynamic(this, &ALFPTurnManager::OnEnemyPlanMoveComplete);
279→    }
280→    else
281→    {
282→        // 没有移动，直接推进下一个敌人
283→        ProcessNextEnemyPlan();
284→    }
285→}
286→
287→void ALFPTurnManager::OnEnemyPlanMoveComplete()
288→{
289→    // 解绑委托
290→    if (PlanningMovingEnemy)
291→    {
292→        PlanningMovingEnemy->OnMoveFinished.RemoveDynamic(this, &ALFPTurnManager::OnEnemyPlanMoveComplete);
293→        PlanningMovingEnemy = nullptr;
294→    }
295→
296→    // 移动完成后推进下一个敌人规划
297→    FTimerHandle TimerHandle;
298→    GetWorld()->GetTimerManager().SetTimer(
299→        TimerHandle,
300→        this,
301→        &ALFPTurnManager::ProcessNextEnemyPlan,
302→        EnemyPlanPostMoveDelay,
303→        false
304→    );
305→}
306→
307→void ALFPTurnManager::EndEnemyPlanningPhase()
308→{
309→    BeginActionPhase();
310→}
311→
312→// ==== 行动阶段 ====
313→
314→void ALFPTurnManager::BeginActionPhase()
315→{
316→    SetPhase(EBattlePhase::BP_ActionPhase);
317→
318→    // 开始第一个单位的回合
319→    if (TurnOrderUnits.Num() > 0)
320→    {
321→        BeginUnitTurn(TurnOrderUnits[0]);
322→    }
323→}
324→
325→void ALFPTurnManager::BeginUnitTurn(ALFPTacticsUnit* Unit)
326→{
327→    if (bBattleEnded) return;
328→
329→    OnTurnChanged.Broadcast();
330→
331→    CurrentUnit = Unit;
332→
333→    ALFPTacticsPlayerController* PC = GetWorld()->GetFirstPlayerController<ALFPTacticsPlayerController>();
334→
335→    // 敌方单位在行动阶段：执行预定计划
336→    if (Unit->IsEnemy() && CurrentPhase == EBattlePhase::BP_ActionPhase)
337→    {
338→        if (PC)
339→        {
340→            PC->HideSkillSelection();
341→        }
342→
343→        Unit->OnTurnStarted();
344→
345→        ExecuteEnemyPlan(Unit);
346→        return;
347→    }
348→
349→    // 玩家单位：保持原有逻辑
350→    if (Unit)
351→    {
352→        Unit->OnTurnStarted();
353→    }
354→
355→    if (PC)
356→    {
357→        PC->OnTurnStarted(Unit);
358→        PC->SelectUnit(Unit);
359→        PC->HandleSkillSelection();
360→    }
361→}
362→
363→void ALFPTurnManager::ExecuteEnemyPlan(ALFPTacticsUnit* Unit)
364→{
365→    const FEnemyActionPlan& Plan = GetPlanForEnemy(Unit);
366→
367→    if (Plan.bIsValid && Plan.PlannedSkill)
368→    {
369→        // 在原定目标格子释放技能（即使目标已死亡）
370→        // AP 已在规划阶段 AllocateEnemySkills 中扣除
371→        Unit->ExecuteSkill(Plan.PlannedSkill, Plan.TargetTile);
372→    }
373→
374→    // 清除头顶技能图标
375→    Unit->ClearActionPlan();
376→
377→    // 短延时后结束回合（让玩家看到技能效果）
378→    FTimerHandle TimerHandle;
379→    GetWorld()->GetTimerManager().SetTimer(TimerHandle, [this, Unit]()
380→    {
381→        Unit->SetHasActed(true);
382→        PassTurn();
383→    }, 0.5f, false);
384→}
385→
386→void ALFPTurnManager::EndUnitTurn(ALFPTacticsUnit* Unit)
387→{
388→    if (Unit)
389→    {
390→        Unit->OnTurnEnded();
391→    }
392→
393→    // 通知玩家控制器
394→    if (ALFPTacticsPlayerController* PC = GetWorld()->GetFirstPlayerController<ALFPTacticsPlayerController>())
395→    {
396→        PC->OnTurnEnded(Unit);
397→    }
398→}
399→
400→void ALFPTurnManager::PassTurn()
401→{
402→    if (bBattleEnded) return;
403→
404→    if (TurnOrderUnits.IsEmpty())
405→    {
406→        return;
407→    }
408→
409→    // 结束当前单位回合
410→    if (CurrentUnit)
411→    {
412→        EndUnitTurn(CurrentUnit);
413→    }
414→
415→    // 找到下一个未行动的单位
416→    int32 CurrentIndex = CurrentUnit ? TurnOrderUnits.Find(CurrentUnit) : -1;
417→    int32 StartIndex = (CurrentIndex + 1) % TurnOrderUnits.Num();
418→
419→    // 检查所有单位是否行动完毕
420→    bool TurnOrderUnitsActed = true;
421→    for (ALFPTacticsUnit* Unit : TurnOrderUnits)
422→    {
423→        if (Unit && Unit->IsAlive() && !Unit->HasActed())
424→        {
425→            TurnOrderUnitsActed = false;
426→            break;
427→        }
428→    }
429→
430→    if (TurnOrderUnitsActed)
431→    {
432→        // 所有单位行动完毕，结束回合
433→        EndCurrentRound();
434→    }
435→    else
436→    {
437→        // 寻找下一个未行动单位
438→        for (int32 i = 0; i < TurnOrderUnits.Num(); i++)
439→        {
440→            int32 Index = (StartIndex + i) % TurnOrderUnits.Num();
441→            ALFPTacticsUnit* NextUnit = TurnOrderUnits[Index];
442→
443→            if (NextUnit && NextUnit->IsAlive() && !NextUnit->HasActed())
444→            {
445→                BeginUnitTurn(NextUnit);
446→                return;
447→            }
448→        }
449→
450→        // 没有找到未行动单位，结束回合
451→        EndCurrentRound();
452→    }
453→}
454→
455→void ALFPTurnManager::OnUnitFinishedAction(ALFPTacticsUnit* Unit)
456→{
457→    if (Unit == CurrentUnit)
458→    {
459→        Unit->SetHasActed(true);
460→
461→        // 自动传递回合
462→        PassTurn();
463→    }
464→}
465→
466→void ALFPTurnManager::RegisterUnit(ALFPTacticsUnit* Unit)
467→{
468→    if (Unit && !TurnOrderUnits.Contains(Unit))
469→    {
470→        TurnOrderUnits.Add(Unit);
471→
472→        // 如果游戏已经开始，重新排序
473→        if (bIsInRound)
474→        {
475→            SortUnitsBySpeed();
476→        }
477→    }
478→}
479→
480→void ALFPTurnManager::UnregisterUnit(ALFPTacticsUnit* Unit)
481→{
482→    if (Unit)
483→    {
484→        bool bWasCurrentUnit = (Unit == CurrentUnit);
485→        TurnOrderUnits.Remove(Unit);
486→
487→        // 先检查战斗结束条件
488→        CheckBattleEnd();
489→
490→        // 如果战斗未结束且当前单位被移除，传递回合
491→        if (!bBattleEnded && bWasCurrentUnit)
492→        {
493→            PassTurn();
494→        }
495→    }
496→}
