498→const FEnemyActionPlan& ALFPTurnManager::GetPlanForEnemy(ALFPTacticsUnit* Enemy) const
499→{
500→    for (const FEnemyActionPlan& Plan : EnemyActionPlans)
501→    {
502→        if (Plan.EnemyUnit == Enemy)
503→        {
504→            return Plan;
505→        }
506→    }
507→    return EmptyPlan;
508→}
