510→// ==== 阵营行动点 ====
511→
512→int32 ALFPTurnManager::GetFactionAP(EUnitAffiliation Faction) const
513→{
514→    const int32* AP = FactionCurrentAP.Find(Faction);
515→    return AP ? *AP : 0;
516→}
517→
518→bool ALFPTurnManager::HasEnoughFactionAP(EUnitAffiliation Faction, int32 Amount) const
519→{
520→    return GetFactionAP(Faction) >= Amount;
521→}
522→
523→void ALFPTurnManager::ConsumeFactionAP(EUnitAffiliation Faction, int32 Amount)
524→{
525→    if (int32* AP = FactionCurrentAP.Find(Faction))
526→    {
527→        *AP = FMath::Max(0, *AP - Amount);
528→        OnFactionAPChanged.Broadcast(Faction, *AP);
529→    }
530→}
