506→void ALFPTacticsUnit::ApplyDamageToTarget(ALFPTacticsUnit* Target)
507→{
508→    if (!Target || Target->bIsDead) return;
509→
510→    // 基础伤害计算
511→    int32 Damage = AttackPower;
512→
513→    // 伤害随机浮动（10% 范围）
