650→
651→    // 距离因素（越近威胁越大）
652→    int32 Distance = FLFPHexCoordinates::Distance(
653→        GetCurrentCoordinates(),
654→        Target->GetCurrentCoordinates()
655→    );
656→    float DistanceFactor = 1.0f / FMath::Max(Distance, 1);
657→
658→    //// 应用行为数据
659→    //if (BehaviorData)
660→    //{
661→    //    if (BehaviorData->bPrioritizeWeakTargets)
662→    //    {
663→    //        // 增加对低血量目标的权重
664→    //        float HealthRatio = (float)Target->GetCurrentHealth() / Target->GetMaxHealth();
665→    //        // 血量越低，威胁值越高
666→    //    }
667→
668→    //    // 应用攻击性系数
669→    //    ThreatValue *= BehaviorData->Aggressiveness;
670→    //}
671→
672→    return ThreatValue * DistanceFactor;
673→}
