675→float ALFPTacticsUnit::CalculatePositionValue(ALFPHexTile* Tile, ALFPTacticsUnit* Target)
676→{
677→    if (!Tile || !Target) return 0.0f;
678→
679→    float PositionValue = 0.0f;
680→
681→    // 1. 离目标越近越好
682→    int32 DistanceToTarget = FLFPHexCoordinates::Distance(
683→        Tile->GetCoordinates(),
684→        Target->GetCurrentCoordinates()
685→    );
686→    PositionValue += 10.0f / FMath::Max(DistanceToTarget, 1);
687→
688→    // 2. 如果在攻击范围内额外加分
689→    if (DistanceToTarget <= GetAttackRange())
690→    {
691→        PositionValue += 20.0f;
692→    }
693→
694→    //// 3. 靠近其他敌方单位（团队协作加分）
695→    //TArray<AActor*> EnemyUnits;
696→    //UGameplayStatics::GetAllActorsOfClass(GetWorld(), ALFPTacticsUnit::StaticClass(), EnemyUnits);
697→
698→    //for (AActor* Actor : EnemyUnits)
